"> {\n  const stacks: Array<\"typescript\" | \"python\" | \"godot\" | \"rust\" | \"go\" | \"unknown\"> = [];\n  if (existsSync(join(projectRoot, \"tsconfig.json\")) || existsSync(join(projectRoot, \"package.json\"))) {\n    stacks.push(\"typescript\");\n  }\n  if (\n    existsSync(join(projectRoot, \"pyproject.toml\")) ||\n    existsSync(join(projectRoot, \"requirements.txt\")) ||\n    existsSync(join(projectRoot, \"setup.py\")) ||\n    existsSync(join(projectRoot, \"Pipfile\"))\n  ) {\n    stacks.push(\"python\");\n  }\n  if (existsSync(join(projectRoot, \"project.godot\"))) stacks.push(\"godot\");\n  if (existsSync(join(projectRoot, \"Cargo.toml\"))) stacks.push(\"rust\");\n  if (existsSync(join(projectRoot, \"go.mod\"))) stacks.push(\"go\");\n  if (stacks.length === 0) stacks.push(\"unknown\");\n  return stacks;\n}\n\nfunction buildVerificationConfig(projectRoot: string): Partial<VerificationPipelineConfig> {\n  const hooks: ToolHook[] = [];\n  let scripts: Record<string, string> = {};\n  const stacks = detectProjectStacks(projectRoot);\n  console.log(`[server] project stacks detected at ${projectRoot}: ${stacks.join(\", \")}`);\n\n  const packageJsonPath = join(projectRoot, \"package.json\");\n  if (existsSync(packageJsonPath)) {\n    try {\n      const packageJson = JSON.parse(readFileSync(packageJsonPath, \"utf-8\")) as {\n        scripts?: Record<string, string>;\n      };\n      scripts = packageJson.scripts ?? {};\n    } catch {\n      scripts = {};\n    }\n  }\n\n  if (typeof scripts.lint === \"string\" && scripts.lint.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Lint\",\n      command: \"npm\",\n      args: [\"run\", \"lint\"],\n      kind: \"lint\",\n    }));\n  }\n\n  const tsconfigPath = join(projectRoot, \"tsconfig.json\");\n  if (existsSync(tsconfigPath)) {\n    hooks.push(createTypecheckHook({ project: tsconfigPath }));\n  }\n\n  if (typeof scripts.test === \"string\" && scripts.test.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Tests\",\n      command: \"npm\",\n      args: [\"run\", \"test\"],\n      kind: \"tests\",\n    }));\n  }\n\n  // Language-agnostic hooks. The verifier runs every registered hook\n  // against the ACTIVE workspace at dispatch time (cwd is per-run, not\n  // per-boot). We can't know at boot whether a given run will target a\n  // Python repo or a Godot repo — so we register the hooks\n  // unconditionally, guarded by their own \"are there files to check?\"\n  // logic, and let them no-op on repos that don't match.\n  //\n  // Python: syntax-check every .py file with python3 -m py_compile. On\n  // a TS repo with no .py files, `xargs -r` makes the command a no-op\n  // and exits 0. On a Python repo it catches import typos / unmatched\n  // parens / unterminated strings. Only registered if python3 is on\n  // PATH.\n  if (hasExecutableOnPath(\"python3\")) {\n    hooks.push(createCustomHook({\n      name: \"Python Syntax\",\n      command: \"sh\",\n      args: [\"-c\", \"find . -type f -name '*.py' -not -path './.venv/*' -not -path './venv/*' -not -path './__pycache__/*' -not -path './node_modules/*' -not -path './.git/*' 2>/dev/null | head -500 | xargs -r python3 -m py_compile\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Godot: headless --check-only validates scripts + scenes. The\n  // `--check-only` flag exits 0 on success, nonzero if any script\n  // fails to parse. Only registered if the godot binary is on PATH\n  // AND this run's cwd has a project.godot — the sh wrapper short-\n  // circuits on non-Godot repos.\n  if (hasExecutableOnPath(\"godot\")) {\n    hooks.push(createCustomHook({\n      name: \"Godot Check\",\n      command: \"sh\",\n      args: [\"-c\", \"[ -f project.godot ] || exit 0; godot --headless --quit --check-only\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Required checks: whichever typecheck-class hooks we managed to\n  // register. An empty list means the verifier won't fail closed on\n  // \"missing required checks\" — for an unknown-stack repo, the diff /\n  // contract / cross-file stages still run and still gate.\n  const requiredChecks = hooks.some((h) => h.kind === \"typecheck\")\n    ? [\"typecheck\"] as const\n    : [] as const;\n\n  return {\n    hooks,\n    requiredChecks: [...requiredChecks],\n    strictMode: process.env[\"AEDIS_STRICT_MODE\"] === \"true\",\n  };\n}\n\n/**\n * Cheap which(1): returns true if the command resolves on PATH. Used\n * so we don't register hooks that would blow up with ENOENT.\n */\nfunction hasExecutableOnPath(cmd: string): boolean {\n  try {\n    const paths = (process.env[\"PATH\"] ?? \"\").split(\":\").filter(Boolean);\n    for (const p of paths) {\n      if (existsSync(join(p, cmd))) return true;\n    }\n    return false;\n  } catch {\n    return false;\n  }\n}\n\nfunction buildDefaultRegistry(projectRoot: string, verificationConfig: Partial<VerificationPipelineConfig>): WorkerRegistry {\n  const registry = new WorkerRegistry();\n  registry.register(new ScoutWorker({ projectRoot }));\n  registry.register(new BuilderWorker({ projectRoot }));\n  registry.register(new CriticWorker({ projectRoot }));\n  registry.register(new VerifierWorker({\n    hooks: verificationConfig.hooks ?? [],\n    verificationConfig,\n  }));\n  registry.register(new IntegratorWorker());\n  console.log(\"[server] WorkerRegistry: 5 workers registered — scout, builder, critic, verifier, integrator\");\n  return registry;\n}\n\n// ─── Resolve ui/ directory relative to this file ─────────────────────\n\nconst __filename = fileURLToPath(import.meta.url);\nconst __dirname = dirname(__filename);\n\nfunction resolveUiRoot(): string {\n  const siblingUi = join(__dirname, \"..\", \"ui\");\n  if (existsSync(siblingUi)) return siblingUi;\n\n  // Built output lives in dist/server, while source ui/ stays at repo-root/ui.\n  const repoUi = join(__dirname, \"..\", \"..\", \"ui\");\n  if (existsSync(repoUi)) return repoUi;\n\n  return siblingUi;\n}\n\nconst UI_ROOT = resolveUiRoot();\n\n// ─── Boot ────────────────────────────────────────────────────────────\n\nexport async function createServer(\n  config: Partial<ServerConfig> = {},\n  trustProfile?: TrustProfile,\n  workerRegistry?: WorkerRegistry\n): Promise<ReturnType<typeof Fastify>> {\n  const cfg: ServerConfig = { ...DEFAULT_CONFIG, ...config };\n  const verificationConfig = buildVerificationConfig(cfg.projectRoot);\n  const registry = workerRegistry ?? buildDefaultRegistry(cfg.projectRoot, verificationConfig);\n  const profile = trustProfile ?? defaultTrustProfile();\n\n  const eventBus = createEventBus();\n  const receiptStore = new ReceiptStore(cfg.projectRoot);\n  const recovery = await receiptStore.markIncompleteRunsCrashed(\n    `Server restarted on ${new Date().toISOString()} before the run reached a terminal state`,\n  );\n  if (recovery.runsRecovered > 0) {\n    console.log(\n      `[server] STARTUP RECOVERY: ${recovery.runsRecovered} run(s) marked INTERRUPTED; ` +\n      `orphan workspaces=${recovery.orphanWorkspaces.length} ` +\n      `(removed=${recovery.orphanWorkspaces.filter((o) => o.removed).length})`,\n    );\n    for (const orphan of recovery.orphanWorkspaces) {\n      console.log(\n        `[server] STARTUP RECOVERY: workspace ${orphan.workspacePath} — ` +\n        (orphan.removed ? \"cleaned\" : `FAILED: ${orphan.error ?? \"unknown\"}`),\n      );\n    }\n  }\n\n  // Auto-promote is opt-in via env (AEDIS_AUTO_PROMOTE=true). When set,\n  // a run that finishes with a clean VERIFIED_SUCCESS classification\n  // has its workspace commit automatically applied to the source repo\n  // as a real commit. Without it, runs land in the workspace only and\n  // require an explicit POST /tasks/:id/promote.\n  const autoPromoteOnSuccess = process.env[\"AEDIS_AUTO_PROMOTE\"] === \"true\";\n  if (autoPromoteOnSuccess) {\n    console.log(\"[server] AEDIS_AUTO_PROMOTE=true — clean runs will auto-promote to source repo\");\n  }\n\n  const coordinator = new Coordinator(\n    {\n      projectRoot: cfg.projectRoot,\n      verificationConfig,\n      autoPromoteOnSuccess,\n      ...cfg.coordinatorConfig,\n    },\n    profile,\n    registry,\n    eventBus,\n    receiptStore,\n  );\n\n  const ctx: ServerContext = {\n    coordinator,\n    eventBus,\n    receiptStore,\n    workerRegistry: registry,\n    config: cfg,\n    startedAt: new Date().toISOString(),\n  };\n\n  // ─── Fastify instance ──────────────────────────────────────────\n\n  const server = Fastify({\n    logger: {\n      level: \"info\",\n    },\n  });\n\n  // ─── Plugins ───────────────────────────────────────────────────\n\n  await server.register(cors, {\n    origin: true,\n    methods: [\"GET\", \"POST\", \"DELETE\", \"OPTIONS\"],\n  });\n\n  await server.register(websocket);\n\n  // ─── Static files: ui/ at /ui/* ────────────────────────────────\n\n  await server.register(fastifyStatic, {\n    root: UI_ROOT,\n    prefix: \"/ui/\",\n  });\n\n  // ─── GET / → serve ui/index.html directly ─────────────────────\n\n  const indexHtmlPath = join(UI_ROOT, \"index.html\");\n  let indexHtml: string;\n  try {\n    indexHtml = readFileSync(indexHtmlPath, \"utf-8\");\n  } catch {\n    indexHtml = \"<html><body><h1>Aedis</h1><p>ui/index.html not found</p></body></html>\";\n  }\n\n  server.get(\"/\", async (_request, reply) => {\n    reply.type(\"text/html\").send(indexHtml);\n  });\n\n  // ─── Auth middleware ───────────────────────────────────────────\n\n  server.addHook(\n    \"onRequest\",\n    createTailscaleAuth({\n      enabled: !cfg.disableAuth,\n      allowedCidrs: cfg.allowedCidrs ?? [],\n    })\n  );\n\n  // ─── Decorate with context ────────────────────────────────────\n\n  server.decorate(\"ctx\", ctx);\n\n  // ─── Routes ────────────────────────────────────────────────────\n\n  await server.register(taskRoutes, { prefix: \"/tasks\" });\n  await server.register(runRoutes, { prefix: \"/runs\" });\n  await server.register(workerRoutes, { prefix: \"/workers\" });\n  // External API layer — /api/* mirrors the internal routes for external consumers\n  // (Crucibulum, CLI tools) that expect the /api prefix convention.\n  await server.register(workerRoutes, { prefix: \"/api/workers\" });\n  await server.register(taskRoutes, { prefix: \"/api/tasks\" });\n  await server.register(sessionRoutes, { prefix: \"/api/sessions\" });\n  await server.register(runRoutes, { prefix: \"/api/runs\" });\n  await server.register(metricsRoutes, { prefix: \"/api/metrics\" });\n  await server.register(healthRoutes);\n  await server.register(configRoutes, { prefix: \"/config\" });\n  await server.register(providerRoutes, { prefix: \"/config/providers\" });\n  // Metrics + External API Layer v1 — read-only external surface.\n  await server.register(costRoutes, { prefix: \"/cost\" });\n  await server.register(metricsRoutes, { prefix: \"/metrics\" });\n  await server.register(loquiRoutes, { prefix: \"/loqui\" });\n  await server.register(trustRoutes, { prefix: \"/trust\" });\n  await server.register(proveRoutes, { prefix: \"/prove\" });\n  await server.register(reliabilityRoutes, { prefix: \"/reliability\" });\n  await server.register(campaignRoutes, { prefix: \"/campaign\" });\n  await server.register(sessionRoutes, { prefix: \"/sessions\" });\n  await server.register(memoryRoutes, { prefix: \"/memory\" });\n\n  // ─── Approval gate endpoints ──────────────────────────────────\n\n  server.get(\"/approvals/pending\", async (_req, reply) => {\n    const pending = coordinator.getPendingApprovals();\n    reply.send({ ok: true, pending });\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/approve\", async (req, reply) => {\n    const result = await coordinator.approveRun(req.params.runId);\n    reply.send(result);\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/reject\", async (req, reply) => {\n    const result = await coordinator.rejectRun(req.params.runId);\n    reply.send(result);\n  });\n\n  // ─── WebSocket endpoint ────────────────────────────────────────\n\n  server.register(async function (fastify) {\n    fastify.get(\"/ws\", { websocket: true }, (socket /* WebSocket */, req) => {\n\n      // Parse optional event filter from query\n      const url = new URL(req.url ?? \"/\", `http://${req.headers.host ?? \"localhost\"}`);\n      const filterParam = url.searchParams.get(\"events\");\n      const filter = filterParam\n        ? (filterParam.split(\",\") as any[])\n        : undefined;\n\n      eventBus.addClient(socket as any, filter);\n\n      // Send welcome message\n      try {\n        socket.send(JSON.stringify({\n          type: \"connected\",\n          timestamp: new Date().toISOString(),\n          message: \"Aedis WebSocket connected\",\n          clients: eventBus.clientCount(),\n        }));\n      } catch {\n        // Socket may have closed\n      }\n\n      // Keepalive ping every 30s\n      const keepalive = setInterval(() => {\n        try {\n          if (socket.readyState === 1) {\n            socket.ping();\n          } else {\n            clearInterval(keepalive);\n          }\n        } catch {\n          clearInterval(keepalive);\n        }\n      }, 30_000);\n\n      socket.on(\"close\", () => {\n        clearInterval(keepalive);\n        eventBus.removeClient(socket as any);\n      });\n\n      socket.on(\"error\", () => {\n        clearInterval(keepalive);\n        eventBus.removeClient(socket as any);\n      });\n\n      // Handle client messages\n      socket.on(\"message\", (data: Buffer) => {\n        try {\n          const msg = JSON.parse(data.toString());\n          if (msg.type === \"ping\") {\n            socket.send(JSON.stringify({ type: \"pong\", timestamp: new Date().toISOString() }));\n          }\n          if (msg.type === \"subscribe\") {\n            socket.send(JSON.stringify({\n              type: \"subscribed\",\n              taskId: msg.taskId,\n              runId: msg.runId,\n              timestamp: new Date().toISOString(),\n            }));\n          }\n        } catch {\n          // Ignore malformed messages\n        }\n      });\n    });\n  });\n\n  return server;\n}\n\n// ─── Standalone boot ─────────────────────────────────────────────────\n\nexport async function startServer(\n  config: Partial<ServerConfig> = {},\n  trustProfile?: TrustProfile,\n  workerRegistry?: WorkerRegistry\n): Promise<void> {\n  const cfg = { ...DEFAULT_CONFIG, ...config };\n  const server = await createServer(cfg, trustProfile, workerRegistry);\n\n  try {\n    const address = await server.listen({ port: cfg.port, host: cfg.host });\n    server.log.info(`Aedis server listening on ${address}`);\n    server.log.info(`WebSocket available at ws://${cfg.host}:${cfg.port}/ws`);\n    server.log.info(`UI available at http://${cfg.host}:${cfg.port}/`);\n  } catch (err) {\n    server.log.error(err);\n    process.exit(1);\n  }\n\n  // Graceful shutdown\n  const shutdown = async () => {\n    server.log.info(\"Shutting down Aedis server...\");\n    await server.close();\n    process.exit(0);\n  };\n\n  process.on(\"SIGINT\", shutdown);\n  process.on(\"SIGTERM\", shutdown);\n}\n\n// ─── Self-boot when run directly ─────────────────────────────────────\n\nconst isDirectRun =\n  process.argv[1]?.endsWith(\"server/index.js\") ||\n  process.argv[1]?.endsWith(\"server/index.ts\");\n\nif (isDirectRun) {\n  startServer().catch((err) => {\n    console.error(\"Aedis server failed to start:\", err);\n    process.exit(1);\n  });\n}\n\n// ─── Type augmentation for Fastify ───────────────────────────────────\n\ndeclare module \"fastify\" {\n  interface FastifyInstance {\n    ctx: ServerContext;\n  }\n}\n\n\n\nRelevant context:\nFILE: server/index.ts\n/**\n * Aedis Server — Fastify + WebSocket on port 18796.\n *\n * Entry point for the Aedis API. Mounts all route files,\n * connects to the Coordinator, and streams events over WebSocket.\n * Serves ui/ as static files at / and /ui/*.\n *\n * Can be run directly: node server/index.js\n */\n\nimport \"dotenv/config\";\n\nimport { existsSync, readFileSync } from \"fs\";\nimport { fileURLToPath } from \"url\";\nimport { dirname, join } from \"path\";\nimport Fastify from \"fastify\";\nimport websocket from \"@fastify/websocket\";\nimport fastifyStatic from \"@fastify/static\";\nimport cors from \"@fastify/cors\";\n\nimport { createTailscaleAuth } from \"./middleware/auth.js\";\nimport { createEventBus, type EventBus } from \"./websocket.js\";\nimport { Coordinator, type CoordinatorConfig } from \"../core/coordinator.js\";\nimport { ReceiptStore } from \"../core/receipt-store.js\";\nimport {\n  createCustomHook,\n  createTypecheckHook,\n  type ToolHook,\n  type VerificationPipelineConfig,\n} from \"../core/verification-pipeline.js\";\nimport { WorkerRegistry } from \"../workers/base.js\";\nimport { ScoutWorker } from \"../workers/scout.js\";\nimport { BuilderWorker } from \"../workers/builder.js\";\nimport { CriticWorker } from \"../workers/critic.js\";\nimport { VerifierWorker } from \"../workers/verifier.js\";\nimport { IntegratorWorker } from \"../workers/integrator.js\";\nimport type { TrustProfile } from \"../router/trust-router.js\";\n\nimport { costRoutes } from \"./routes/cost.js\";\nimport { taskRoutes } from \"./routes/tasks.js\";\nimport { runRoutes } from \"./routes/runs.js\";\nimport { workerRoutes } from \"./routes/workers.js\";\nimport { healthRoutes } from \"./routes/health.js\";\nimport { configRoutes } from \"./routes/config.js\";\nimport { providerRoutes } from \"./routes/providers.js\";\nimport { metricsRoutes } from \"./routes/metrics.js\";\nimport { loquiRoutes } from \"./routes/loqui.js\";\nimport { trustRoutes } from \"./routes/trust.js\";\nimport { proveRoutes } from \"./routes/prove.js\";\nimport { reliabilityRoutes } from \"./routes/reliability.js\";\nimport { campaignRoutes } from \"./routes/campaign.js\";\nimport { sessionRoutes } from \"./routes/sessions.js\";\nimport { memoryRoutes } from \"./routes/memory.js\";\n\n// ─── Types ───────────────────────────────────────────────────────────\n\nexport interface ServerConfig {\n  port: number;\n  host: string;\n  projectRoot: string;\n  coordinatorConfig?: Partial<CoordinatorConfig>;\n  /** Disable Tailscale auth (for local dev) */\n  disableAuth?: boolean;\n  /** Additional allowed CIDRs */\n  allowedCidrs?: string[];\n}\n\nconst DEFAULT_CONFIG: ServerConfig = {\n  port: 18796,\n  host: \"0.0.0.0\",\n  projectRoot: process.cwd(),\n};\n\n// ─── Server Context (shared across routes) ───────────────────────────\n\nexport interface ServerContext {\n  coordinator: Coordinator;\n  eventBus: EventBus;\n  receiptStore: ReceiptStore;\n  workerRegistry: WorkerRegistry;\n  config: ServerConfig;\n  startedAt: string;\n}\n\n// ─── Defaults for standalone boot ────────────────────────────────────\n\nfunction defaultTrustProfile(): TrustProfile {\n  return {\n    scores: new Map(),\n    tierThresholds: { fast: 0.6, standard: 0.75, premium: 0.9 },\n  };\n}\n\n/**\n * Build a WorkerRegistry with all 5 worker types registered.\n */\n/**\n * Detect the primary language/stack of a project so the verifier can\n * pick the right hooks. Returns an ordered list of detected stacks —\n * a repo with both package.json AND pyproject.toml (rare but real)\n * gets both. Godot projects are detected via project.godot.\n */\nfunction detectProjectStacks(projectRoot: string): ReadonlyArray<\"typescript\" | \"python\" | \"godot\" | \"rust\" | \"go\" | \"unknown\"> {\n  const stacks: Array<\"typescript\" | \"python\" | \"godot\" | \"rust\" | \"go\" | \"unknown\"> = [];\n  if (existsSync(join(projectRoot, \"tsconfig.json\")) || existsSync(join(projectRoot, \"package.json\"))) {\n    stacks.push(\"typescript\");\n  }\n  if (\n    existsSync(join(projectRoot, \"pyproject.toml\")) ||\n    existsSync(join(projectRoot, \"requirements.txt\")) ||\n    existsSync(join(projectRoot, \"setup.py\")) ||\n    existsSync(join(projectRoot, \"Pipfile\"))\n  ) {\n    stacks.push(\"python\");\n  }\n  if (existsSync(join(projectRoot, \"project.godot\"))) stacks.push(\"godot\");\n  if (existsSync(join(projectRoot, \"Cargo.toml\"))) stacks.push(\"rust\");\n  if (existsSync(join(projectRoot, \"go.mod\"))) stacks.push(\"go\");\n  if (stacks.length === 0) stacks.push(\"unknown\");\n  return stacks;\n}\n\nfunction buildVerificationConfig(projectRoot: string): Partial<VerificationPipelineConfig> {\n  const hooks: ToolHook[] = [];\n  let scripts: Record<string, string> = {};\n  const stacks = detectProjectStacks(projectRoot);\n  console.log(`[server] project stacks detected at ${projectRoot}: ${stacks.join(\", \")}`);\n\n  const packageJsonPath = join(projectRoot, \"package.json\");\n  if (existsSync(packageJsonPath)) {\n    try {\n      const packageJson = JSON.parse(readFileSync(packageJsonPath, \"utf-8\")) as {\n        scripts?: Record<string, string>;\n      };\n      scripts = packageJson.scripts ?? {};\n    } catch {\n      scripts = {};\n    }\n  }\n\n  if (typeof scripts.lint === \"string\" && scripts.lint.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Lint\",\n      command: \"npm\",\n      args: [\"run\", \"lint\"],\n      kind: \"lint\",\n    }));\n  }\n\n  const tsconfigPath = join(projectRoot, \"tsconfig.json\");\n  if (existsSync(tsconfigPath)) {\n    hooks.push(createTypecheckHook({ project: tsconfigPath }));\n  }\n\n  if (typeof scripts.test === \"string\" && scripts.test.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Tests\",\n      command: \"npm\",\n      args: [\"run\", \"test\"],\n      kind: \"tests\",\n    }));\n  }\n\n  // Language-agnostic hooks. The verifier runs every registered hook\n  // against the ACTIVE workspace at dispatch time (cwd is per-run, not\n  // per-boot). We can't know at boot whether a given run will target a\n  // Python repo or a Godot repo — so we register the hooks\n  // unconditionally, guarded by their own \"are there files to check?\"\n  // logic, and let them no-op on repos that don't match.\n  //\n  // Python: syntax-check every .py file with python3 -m py_compile. On\n  // a TS repo with no .py files, `xargs -r` makes the command a no-op\n  // and exits 0. On a Python repo it catches import typos / unmatched\n  // parens / unterminated strings. Only registered if python3 is on\n  // PATH.\n  if (hasExecutableOnPath(\"python3\")) {\n    hooks.push(createCustomHook({\n      name: \"Python Syntax\",\n      command: \"sh\",\n      args: [\"-c\", \"find . -type f -name '*.py' -not -path './.venv/*' -not -path './venv/*' -not -path './__pycache__/*' -not -path './node_modules/*' -not -path './.git/*' 2>/dev/null | head -500 | xargs -r python3 -m py_compile\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Godot: headless --check-only validates scripts + scenes. The\n  // `--check-only` flag exits 0 on success, nonzero if any script\n  // fails to parse. Only registered if the godot binary is on PATH\n  // AND this run's cwd has a project.godot — the sh wrapper short-\n  // circuits on non-Godot repos.\n  if (hasExecutableOnPath(\"godot\")) {\n    hooks.push(createCustomHook({\n      name: \"Godot Check\",\n      command: \"sh\",\n      args: [\"-c\", \"[ -f project.godot ] || exit 0; godot --headless --quit --check-only\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Required checks: whichever typecheck-class hooks we managed to\n  // register. An empty list means the verifier won't fail closed on\n  // \"missing required checks\" — for an unknown-stack repo, the diff /\n  // contract / cross-file stages still run and still gate.\n  const requiredChecks = hooks.some((h) => h.kind === \"typecheck\")\n    ? [\"typecheck\"] as const\n    : [] as const;\n\n  return {\n    hooks,\n    requiredChecks: [...requiredChecks],\n    strictMode: process.env[\"AEDIS_STRICT_MODE\"] === \"true\",\n  };\n}\n\n/**\n * Cheap which(1): returns true if the command resolves on PATH. Used\n * so we don't register hooks that would blow up with ENOENT.\n */\nfunction hasExecutableOnPath(cmd: string): boolean {\n  try {\n    const paths = (process.env[\"PATH\"] ?? \"\").split(\":\").filter(Boolean);\n    for (const p of paths) {\n      if (existsSync(join(p, cmd))) return true;\n    }\n    return false;\n  } catch {\n    return false;\n  }\n}\n\nfunction buildDefaultRegistry(projectRoot: string, verificationConfig: Partial<VerificationPipelineConfig>): WorkerRegistry {\n  const registry = new WorkerRegistry();\n  registry.register(new ScoutWorker({ projectRoot }));\n  registry.register(new BuilderWorker({ projectRoot }));\n  registry.register(new CriticWorker({ projectRoot }));\n  registry.register(new VerifierWorker({\n    hooks: verificationConfig.hooks ?? [],\n    verificationConfig,\n  }));\n  registry.register(new IntegratorWorker());\n  console.log(\"[server] WorkerRegistry: 5 workers registered — scout, builder, critic, verifier, integrator\");\n  return registry;\n}\n\n// ─── Resolve ui/ directory relative to this file ─────────────────────\n\nconst __filename = fileURLToPath(import.meta.url);\nconst __dirname = dirname(__filename);\n\nfunction resolveUiRoot(): string {\n  const siblingUi = join(__dirname, \"..\", \"ui\");\n  if (existsSync(siblingUi)) return siblingUi;\n\n  // Built output lives in dist/server, while source ui/ stays at repo-root/ui.\n  const repoUi = join(__dirname, \"..\", \"..\", \"ui\");\n  if (existsSync(repoUi)) return repoUi;\n\n  return siblingUi;\n}\n\nconst UI_ROOT = resolveUiRoot();\n\n// ─── Boot ────────────────────────────────────────────────────────────\n\nexport async function createServer(\n  config: Partial<ServerConfig> = {},\n  trustProfile?: TrustProfile,\n  workerRegistry?: WorkerRegistry\n): Promise<ReturnType<typeof Fastify>> {\n  const cfg: ServerConfig = { ...DEFAULT_CONFIG, ...config };\n  const verificationConfig = buildVerificationConfig(cfg.projectRoot);\n  const registry = workerRegistry ?? buildDefaultRegistry(cfg.projectRoot, verificationConfig);\n  const profile = trustProfile ?? defaultTrustProfile();\n\n  const eventBus = createEventBus();\n  const receiptStore = new ReceiptStore(cfg.projectRoot);\n  const recovery = await receiptStore.markIncompleteRunsCrashed(\n    `Server restarted on ${new Date().toISOString()} before the run reached a terminal state`,\n  );\n  if (recovery.runsRecovered > 0) {\n    console.log(\n      `[server] STARTUP RECOVERY: ${recovery.runsRecovered} run(s) marked INTERRUPTED; ` +\n      `orphan workspaces=${recovery.orphanWorkspaces.length} ` +\n      `(removed=${recovery.orphanWorkspaces.filter((o) => o.removed).length})`,\n    );\n    for (const orphan of recovery.orphanWorkspaces) {\n      console.log(\n        `[server] STARTUP RECOVERY: workspace ${orphan.workspacePath} — ` +\n        (orphan.removed ? \"cleaned\" : `FAILED: ${orphan.error ?? \"unknown\"}`),\n      );\n    }\n  }\n\n  // Auto-promote is opt-in via env (AEDIS_AUTO_PROMOTE=true). When set,\n  // a run that finishes with a clean VERIFIED_SUCCESS classification\n  // has its workspace commit automatically applied to the source repo\n  // as a real commit. Without it, runs land in the workspace only and\n  // require an explicit POST /tasks/:id/promote.\n  const autoPromoteOnSuccess = process.env[\"AEDIS_AUTO_PROMOTE\"] === \"true\";\n  if (autoPromoteOnSuccess) {\n    console.log(\"[server] AEDIS_AUTO_PROMOTE=true — clean runs will auto-promote to source repo\");\n  }\n\n  const coordinator = new Coordinator(\n    {\n      projectRoot: cfg.projectRoot,\n      verificationConfig,\n      autoPromoteOnSuccess,\n      ...cfg.coordinatorConfig,\n    },\n    profile,\n    registry,\n    eventBus,\n    receiptStore,\n  );\n\n  const ctx: ServerContext = {\n    coordinator,\n    eventBus,\n    receiptStore,\n    workerRegistry: registry,\n    config: cfg,\n    startedAt: new Date().toISOString(),\n  };\n\n  // ─── Fastify instance ──────────────────────────────────────────\n\n  const server = Fastify({\n    logger: {\n      level: \"info\",\n    },\n  });\n\n  // ─── Plugins ───────────────────────────────────────────────────\n\n  await server.register(cors, {\n    origin: true,\n    methods: [\"GET\", \"POST\", \"DELETE\", \"OPTIONS\"],\n  });\n\n  await server.register(websocket);\n\n  // ─── Static files: ui/ at /ui/* ────────────────────────────────\n\n  await server.register(fastifyStatic, {\n    root: UI_ROOT,\n    prefix: \"/ui/\",\n  });\n\n  // ─── GET / → serve ui/index.html directly ─────────────────────\n\n  const indexHtmlPath = join(UI_ROOT, \"index.html\");\n  let indexHtml: string;\n  try {\n    indexHtml = readFileSync(indexHtmlPath, \"utf-8\");\n  } catch {\n    indexHtml = \"<html><body><h1>Aedis</h1><p>ui/index.html not found</p></body></html>\";\n  }\n\n  server.get(\"/\", async (_request, reply) => {\n    reply.type(\"text/html\").send(indexHtml);\n  });\n\n  // ─── Auth middleware ───────────────────────────────────────────\n\n  server.addHook(\n    \"onRequest\",\n    createTailscaleAuth({\n      enabled: !cfg.disableAuth,\n      allowedCidrs: cfg.allowedCidrs ?? [],\n    })\n  );\n\n  // ─── Decorate with context ────────────────────────────────────\n\n  server.decorate(\"ctx\", ctx);\n\n  // ─── Routes ────────────────────────────────────────────────────\n\n  await server.register(taskRoutes, { prefix: \"/tasks\" });\n  await server.register(runRoutes, { prefix: \"/runs\" });\n  await server.register(workerRoutes, { prefix: \"/workers\" });\n  // External API layer — /api/* mirrors the internal routes for external consumers\n  // (Crucibulum, CLI tools) that expect the /api prefix convention.\n  await server.register(workerRoutes, { prefix: \"/api/workers\" });\n  await server.register(taskRoutes, { prefix: \"/api/tasks\" });\n  await server.register(sessionRoutes, { prefix: \"/api/sessions\" });\n  await server.register(runRoutes, { prefix: \"/api/runs\" });\n  await server.register(metricsRoutes, { prefix: \"/api/metrics\" });\n  await server.register(healthRoutes);\n  await server.register(configRoutes, { prefix: \"/config\" });\n  await server.register(providerRoutes, { prefix: \"/config/providers\" });\n  // Metrics + External API Layer v1 — read-only external surface.\n  await server.register(costRoutes, { prefix: \"/cost\" });\n  await server.register(metricsRoutes, { prefix: \"/metrics\" });\n  await server.register(loquiRoutes, { prefix: \"/loqui\" });\n  await server.register(trustRoutes, { prefix: \"/trust\" });\n  await server.register(proveRoutes, { prefix: \"/prove\" });\n  await server.register(reliabilityRoutes, { prefix: \"/reliability\" });\n  await server.register(campaignRoutes, { prefix: \"/campaign\" });\n  await server.register(sessionRoutes, { prefix: \"/sessions\" });\n  await server.register(memoryRoutes, { prefix: \"/memory\" });\n\n  // ─── Approval gate endpoints ──────────────────────────────────\n\n  server.get(\"/approvals/pending\", async (_req, reply) => {\n    const pending = coordinator.getPendingApprovals();\n    reply.send({ ok: true, pending });\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/approve\", async (req, reply) => {\n    const result = await coordinator.approveRun(req.params.runId);\n    reply.send(result);\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/reject\", async (req, reply) => {\n    const result = await coordinator.rejectRun(req.params.runId);\n    reply.send(result);\n  });\n\n  // ─── WebSocket endpoint ────────────────────────────────────────\n\n  server.register(async function (fastify) {\n    fastify.get(\"/ws\", { websocket: true }, (socket /* WebSocket */, req) => {\n\n      // Parse optional event filter from query\n      const url = new URL(req.url ?? \"/\", `http://${req.headers.host ?? \"localhost\"}`);\n      const filterParam = url.searchParams.get(\"events\");\n      const filter = filterParam\n        ? (filterParam.split(\",\") as any[])\n        : undefined;\n\n      eventBus.addClient(socket as any, filter);\n\n      // Send welcome message\n      try {\n        socket.send(JSON.stringify({\n          type: \"connected\",\n          timestamp: new Date().toISOString(),\n          message: \"Aedis WebSocket connected\",\n          clients: eventBus.clientCount(),\n        }));\n      } catch {\n        // Socket may have closed\n      }\n\n      // Keepalive ping every 30s\n      const keepalive = setInterval(() => {\n        try {\n          if (socket.readyState === 1) {\n            socket.ping();\n          } else {\n            clearInterval(keepalive);\n          }\n        } catch {\n          clearInterval(keepalive);\n        }\n      }, 30_000);\n\n      socket.on(\"close\", () => {\n        clearInterval(keepalive);\n        eventBus.removeClient(socket as any);\n      });\n\n      socket.on(\"error\", () => {\n        clearInterval(keepalive);\n        eventBus.removeClient(socket as any);\n      });\n\n      // Handle client messages\n      socket.on(\"message\", (data: Buffer) => {\n        try {\n          const msg = JSON.parse(data.toString());\n          if (msg.type === \"ping\") {\n            socket.send(JSON.stringify({ type: \"pong\", timestamp: new Date().toISOString() }));\n          }\n          if (msg.type === \"subscribe\") {\n            socket.send(JSON.stringify({\n              type: \"subscribed\",\n              taskId: msg.taskId,\n              runId: msg.runId,\n              timestamp: new Date().toISOString(),\n            }));\n          }\n        } catch {\n          // Ignore malformed messages\n        }\n      });\n    });\n  });\n\n  return server;\n}\n\n// ─── Standalone boot ─────────────────────────────────────────────────\n\nexport async function startServer(\n  config: Partial<ServerConfig> = {},\n  trustProfile?: TrustProfile,\n  workerRegistry?: WorkerRegistry\n): Promise<void> {\n  const cfg = { ...DEFAULT_CONFIG, ...config };\n  const server = await createServer(cfg, trustProfile, workerRegistry);\n\n  try {\n    const address = await server.listen({ port: cfg.port, host: cfg.host });\n    server.log.info(`Aedis server listening on ${address}`);\n    server.log.info(`WebSocket available at ws://${cfg.host}:${cfg.port}/ws`);\n    server.log.info(`UI available at http://${cfg.host}:${cfg.port}/`);\n  } catch (err) {\n    server.log.error(err);\n    process.exit(1);\n  }\n\n  // Graceful shutdown\n  const shutdown = async () => {\n    server.log.info(\"Shutting down Aedis server...\");\n    await server.close();\n    process.exit(0);\n  };\n\n  process.on(\"SIGINT\", shutdown);\n  process.on(\"SIGTERM\", shutdown);\n}\n\n// ─── Self-boot when run directly ─────────────────────────────────────\n\nconst isDirectRun =\n  process.argv[1]?.endsWith(\"server/index.js\") ||\n  process.argv[1]?.endsWith(\"server/index.ts\");\n\nif (isDirectRun) {\n  startServer().catch((err) => {\n    console.error(\"Aedis server failed to start:\", err);\n    process.exit(1);\n  });\n}\n\n// ─── Type augmentation for Fastify ───────────────────────────────────\n\ndeclare module \"fastify\" {\n  interface FastifyInstance {\n    ctx: ServerContext;\n  }\n}\n\n\n---\n\nFILE: server/routes/workers.ts\n/**\n * Worker routes — Query worker pools and status.\n *\n * GET /workers       — All worker pools with status\n * GET /workers/:role — Specific worker pool\n */\n\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \"fastify\";\nimport type { ServerContext } from \"../index.js\";\nimport type { WorkerType } from \"../../workers/base.js\";\n\n// ─── Request Schemas ─────────────────────────────────────────────────\n\ninterface WorkerParams {\n  role: string;\n}\n\n// ─── Routes ──────────────────────────────────────────────────────────\n\nexport const workerRoutes: FastifyPluginAsync = async (fastify) => {\n  const ctx = (): ServerContext => fastify.ctx;\n\n  const WORKER_TYPES: WorkerType[] = [\"scout\", \"builder\", \"critic\", \"verifier\", \"integrator\"];\n\n  /**\n   * GET /workers — All worker pools with status.\n   */\n  fastify.get(\n    \"/\",\n    async (_request: FastifyRequest, reply: FastifyReply) => {\n      const registry = ctx().workerRegistry;\n\n      const pools = WORKER_TYPES.map((type) => {\n        const workers = registry.getWorkers(type);\n        return {\n          role: type,\n          available: workers.length > 0,\n          count: workers.length,\n          workers: workers.map((w) => ({\n            name: w.name,\n            type: w.type,\n          })),\n        };\n      });\n\n      const totalWorkers = pools.reduce((sum, p) => sum + p.count, 0);\n      const availableRoles = pools.filter((p) => p.available).length;\n\n      reply.send({\n        pools,\n        summary: {\n          total_workers: totalWorkers,\n          available_roles: availableRoles,\n          total_roles: WORKER_TYPES.length,\n          fully_staffed: availableRoles === WORKER_TYPES.length,\n        },\n      });\n    }\n  );\n\n  /**\n   * GET /workers/:role — Specific worker pool details.\n   */\n  fastify.get<{ Params: WorkerParams }>(\n    \"/:role\",\n    async (request: FastifyRequest<{ Params: WorkerParams }>, reply: FastifyReply) => {\n      const { role } = request.params;\n\n      if (!WORKER_TYPES.includes(role as WorkerType)) {\n        reply.code(400).send({\n          error: \"Invalid role\",\n          message: `Unknown worker role \"${role}\". Valid roles: ${WORKER_TYPES.join(\", \")}`,\n        });\n        return;\n      }\n\n      const workers = ctx().workerRegistry.getWorkers(role as WorkerType);\n\n      // Check recent activity for these workers\n      const events = ctx().eventBus.recentEvents(100);\n      const workerEvents = events.filter(\n        (e) => (e.payload as any).workerType === role\n      );\n\n      reply.send({\n        role,\n        available: workers.length > 0,\n        count: workers.length,\n        workers: workers.map((w) => ({\n          name: w.name,\n          type: w.type,\n        })),\n        recent_activity: workerEvents.slice(-10).map((e) => ({\n          type: e.type,\n          timestamp: e.timestamp,\n          run_id: (e.payload as any).runId,\n        })),\n      });\n    }\n  );\n};\n\n\n---\n\nFILE: server/routes/tasks.ts\n/**\n * Task routes — Submit, query, and cancel build tasks.\n *\n * POST /tasks       — Submit a new task, returns { task_id, run_id }\n * GET  /tasks/:id   — Status + current run state\n * GET  /tasks/:id/receipts — Full receipt bundle\n * POST /tasks/:id/cancel — Cancel a running task\n * DELETE /tasks/:id — Cancel a running task\n */\n\nimport { randomUUID } from \"crypto\";\nimport { existsSync } from \"fs\";\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \"fastify\";\nimport { askLoqui } from \"../../core/loqui.js\";\nimport { routeLoquiInput, type LoquiRouteDecision } from \"../../core/loqui-router.js\";\nimport type { LoquiIntentContext } from \"../../core/loqui-intent.js\";\nimport { generateDryRun } from \"../../core/dry-run.js\";\nimport type { ServerContext } from \"../index.js\";\n\n// ─── Request/Response Schemas ────────────────────────────────────────\n\ninterface SubmitBody {\n  /** Natural language prompt — also accepted as \"input\" */\n  prompt?: string;\n  input?: string;\n  /** Repo path to operate on */\n  repoPath?: string;\n  exclusions?: string[];\n  quality_bar?: \"minimal\" | \"standard\" | \"hardened\";\n}\n\ninterface TaskParams {\n  id: string;\n}\n\ninterface LoquiBody {\n  question: string;\n  repoPath: string;\n}\n\n/**\n * Unified Loqui route request body. A single freeform input stream\n * that the classifier will route to build / answer / resume /\n * clarify. The `context` field is optional — the UI passes it when\n * it knows about a prior run so the classifier can emit resume_run\n * or status intents safely (see core/loqui-intent.ts Rule B).\n */\ninterface LoquiUnifiedBody {\n  input: string;\n  repoPath: string;\n  context?: LoquiIntentContext;\n}\n\n// ─── In-memory run tracker (bridges POST → Coordinator → WS) ────────\n\ninterface TrackedRun {\n  taskId: string;\n  runId: string;\n  status: \"queued\" | \"running\" | \"complete\" | \"partial\" | \"failed\" | \"cancelled\";\n  prompt: string;\n  submittedAt: string;\n  completedAt: string | null;\n  receipt: unknown | null;\n  error: string | null;\n}\n\nconst trackedRuns = new Map<string, TrackedRun>();\n\nexport function getTrackedRun(taskId: string): TrackedRun | undefined {\n  return trackedRuns.get(taskId);\n}\n\n/**\n * Snapshot of every tracked run, newest first. Read-only — returns\n * a fresh array so callers can iterate / sort / slice without\n * touching the internal Map. Used by the external API layer\n * (Metrics + External API v1) so /metrics, /runs, and /runs/:id\n * can aggregate across the same registry that /tasks writes to,\n * without importing the private Map or creating a second source\n * of truth.\n */\nexport function getAllTrackedRuns(): readonly TrackedRun[] {\n  const out = [...trackedRuns.values()];\n  out.sort((a, b) => (a.submittedAt < b.submittedAt ? 1 : -1));\n  return out;\n}\n\n/** Exported type for the external API routes. */\nexport type { TrackedRun };\n\n/**\n * Result from submitBuildTask — may be a running build, a clarification\n * request, or a decomposition plan.\n */\ntype BuildSubmitResult =\n  | { kind: \"running\"; taskId: string; runId: string; prompt: string; repoPath: string | null }\n  | { kind: \"needs_clarification\"; question: string }\n  | { kind: \"needs_decomposition\"; taskId: string; plan: unknown; message: string };\n\n/**\n * Shared build-submit helper. Dispatches a build task through the\n * Coordinator (via submitWithGates) and registers the tracked run state.\n * Used by both the legacy POST /tasks handler and the new unified POST\n * /tasks/loqui path so we get exactly one code path for \"start a \n// ... [truncated]\n\n---\n\nFILE: server/routes/sessions.ts\n/**\n * Session routes — Create and manage autonomous build sessions.\n *\n * GET    /sessions               — List all sessions (admin/debug)\n * POST   /sessions              — Create a new session\n * GET    /sessions/:id          — Get session state\n * POST   /sessions/:id/cycles   — Trigger one additional cycle\n * DELETE /sessions/:id          — Cancel a session\n * GET    /sessions/:id/receipts — List receipts\n */\n\nimport { randomUUID } from \"crypto\";\nimport type { FastifyPluginAsync } from \"fastify\";\nimport { type ServerContext } from \"../index.js\";\nimport { type AedisSession, type CycleResult } from \"../../types/session.js\";\nimport {\n  createSession,\n  loadSession,\n  saveSession,\n  transitionSession,\n  listAllSessions,\n} from \"../../core/session-store.js\";\nimport { runSession, runOneMoreCycle, startCleanupTimer } from \"../../core/session-coordinator.js\";\n\n// ─── Request schemas ────────────────────────────────────────────────\n\ninterface CreateSessionBody {\n  task: string;           // natural language task intent\n  projectRoot: string;   // path to the project\n  maxCycles?: number;    // optional override (default: 3)\n  maxDurationMs?: number; // optional duration override (default: 30min)\n  goal?: string;         // optional goal description\n  model?: string;        // optional model override\n  constraints?: Record<string, string>;\n}\n\ninterface SessionParams {\n  id: string;\n}\n\n// ─── Routes ──────────────────────────────────────────────────────────\n\nexport const sessionRoutes: FastifyPluginAsync = async (fastify) => {\n  const ctx = (): ServerContext => fastify.ctx;\n\n  // Start cleanup timer on first registration\n  startCleanupTimer(ctx().coordinator);\n\n  /**\n   * GET /sessions — List all sessions with status + cycleCount.\n   * For debugging and admin use.\n   */\n  fastify.get(\n    \"/\",\n    async (request, reply) => {\n      const all = await listAllSessions();\n      return reply.send({\n        ok: true,\n        sessions: all.map(s => ({\n          id: s.id,\n          status: s.status,\n          cycleCount: s.cycleCount,\n          maxCycles: s.maxCycles,\n          createdAt: s.createdAt,\n          updatedAt: s.updatedAt,\n          intent: {\n            userRequest: s.intent.userRequest,\n            projectRoot: s.intent.projectRoot,\n          },\n          terminalReason: s.terminalReason,\n        })),\n        total: all.length,\n      });\n    }\n  );\n\n  /**\n   * POST /sessions — Create a new autonomous session.\n   *\n   * Creates the session and immediately starts running cycles.\n   * Returns the session state after all cycles complete (terminal state).\n   */\n  fastify.post<{ Body: CreateSessionBody }>(\n    \"/\",\n    async (request, reply) => {\n      const { task, projectRoot, maxCycles, maxDurationMs, goal, model, constraints } = request.body ?? {};\n\n      if (!task || !projectRoot) {\n        return reply.status(400).send({\n          ok: false,\n          error: \"Missing required fields: task and projectRoot are required\",\n        });\n      }\n\n      const session = await runSession({\n        coordinator: ctx().coordinator,\n        intent: {\n          userRequest: task,\n          goal: goal ?? task,\n          projectRoot,\n          model,\n          constraints,\n        },\n        maxCycles: maxCycles ?? 3,\n        maxDurationMs: maxDurationMs ?? 30 * 60 * 1000,\n      });\n\n      return reply.send({ ok: true, session });\n    }\n  );\n\n  /**\n   * GET /sessions/:id — Get the current state of a session.\n   */\n  fastify.get<{ Params: SessionParams }>\n// ... [truncated]\n\n---\n\nFILE: server/routes/runs.ts\n/**\n * Run routes — Query build run history, details, and receipts.\n *\n * GET /runs              — Recent runs with summary\n * GET /runs/:id          — Full run detail + task graph\n * GET /runs/:id/integration — Integration judge result\n * GET /runs/:id/receipts — Cost breakdown\n */\n\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \"fastify\";\nimport type { ServerContext } from \"../index.js\";\nimport type { WireMessage } from \"../websocket.js\";\nimport {\n  projectRunList,\n  projectRunDetail,\n  type TrackedRunLike,\n} from \"../../core/metrics.js\";\nimport { getAllTrackedRuns, getTrackedRun } from \"./tasks.js\";\nimport {\n  buildRunDetailResponse,\n  buildRunIntegrationResponse,\n  buildRunListEntry,\n} from \"./run-contracts.js\";\n\n// ─── Request Schemas ─────────────────────────────────────────────────\n\ninterface RunParams {\n  id: string;\n}\n\ninterface RunsQuery {\n  limit?: number;\n  status?: string;\n}\n\n// ─── Routes ──────────────────────────────────────────────────────────\n\nexport const runRoutes: FastifyPluginAsync = async (fastify) => {\n  const ctx = (): ServerContext => fastify.ctx;\n  const resolveRunId = async (id: string): Promise<string> => {\n    const task = await ctx().receiptStore.getTask(id);\n    return task?.runId ?? id;\n  };\n\n  /**\n   * GET /runs — List recent runs with summary.\n   *\n   * Metrics + External API v1: prefers the tracked-run registry\n   * (populated by POST /tasks) so every list item carries the\n   * grounded summary, classification, confidence, and cost from\n   * the RunReceipt. Falls back to the event-bus projection when\n   * the registry is empty (tests, fresh boot, legacy clients).\n   */\n  fastify.get<{ Querystring: RunsQuery }>(\n    \"/\",\n    async (request: FastifyRequest<{ Querystring: RunsQuery }>, reply: FastifyReply) => {\n      const limit = Math.min(request.query.limit ?? 20, 100);\n      const statusFilter = request.query.status;\n\n      const persisted = await ctx().receiptStore.listRuns(limit, statusFilter);\n      if (persisted.length > 0) {\n        reply.send({\n          runs: persisted.map((run) => ({\n            ...buildRunListEntry({\n              id: run.runId,\n              runId: run.runId,\n              status: run.status,\n              classification: run.finalClassification,\n              prompt: run.prompt,\n              summary: run.summary,\n              costUsd: run.costUsd,\n              confidence: run.confidence ?? 0,\n              timestamp: run.updatedAt,\n              completedAt: run.completedAt,\n            }),\n          })),\n          total: persisted.length,\n          source: \"persistent-receipts\",\n        });\n        return;\n      }\n\n      const tracked = getAllTrackedRuns() as unknown as readonly TrackedRunLike[];\n      if (tracked.length > 0) {\n        const projected = projectRunList(tracked, limit)\n          .filter(\n            (run) =>\n              !statusFilter ||\n              run.status === statusFilter ||\n              run.classification === statusFilter,\n          );\n        reply.send({\n          runs: projected.map((run) => buildRunListEntry({\n            id: run.id,\n            runId: run.runId ?? run.id,\n            status: run.status,\n            classification: run.classification,\n            prompt: run.prompt,\n            summary: run.summary,\n            costUsd: run.costUsd,\n            confidence: run.confidence,\n            timestamp: run.timestamp,\n            completedAt: run.completedAt,\n          })),\n          total: projected.length,\n  \n// ... [truncated]\n\n---\n\nFILE: server/routes/reliability.ts\n/**\n * Reliability API — minimal read surface for the reliability harness.\n *\n * Trials are produced by the CLI (`aedis reliability run`) and written\n * to state/reliability/. This route exposes them for inspection without\n * asking the user to cat JSON.\n *\n * GET /reliability/trials         — list trial summaries, newest first\n * GET /reliability/trials/:id     — full trial, including per-task results\n * GET /reliability/trials/latest  — most recently recorded trial\n */\n\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \"fastify\";\n\nimport type { ServerContext } from \"../index.js\";\nimport {\n  listTrials,\n  loadLatestTrial,\n  loadTrial,\n} from \"../../core/reliability-harness.js\";\n\ninterface TrialParams {\n  id: string;\n}\n\nexport const reliabilityRoutes: FastifyPluginAsync = async (fastify) => {\n  const ctx = (): ServerContext => fastify.ctx;\n\n  fastify.get(\"/trials\", async (_req, reply) => {\n    const trials = await listTrials(ctx().config.projectRoot);\n    reply.send({ trials });\n  });\n\n  fastify.get(\"/trials/latest\", async (_req, reply) => {\n    const trial = await loadLatestTrial(ctx().config.projectRoot);\n    if (!trial) {\n      reply.code(404).send({ error: \"Not found\", message: \"no trials recorded\" });\n      return;\n    }\n    reply.send({ trial });\n  });\n\n  fastify.get<{ Params: TrialParams }>(\n    \"/trials/:id\",\n    async (req: FastifyRequest<{ Params: TrialParams }>, reply: FastifyReply) => {\n      const trial = await loadTrial(ctx().config.projectRoot, req.params.id);\n      if (!trial) {\n        reply.code(404).send({\n          error: \"Not found\",\n          message: `trial \"${req.params.id}\" not found`,\n        });\n        return;\n      }\n      reply.send({ trial });\n    },\n  );\n};\n\n\n---\n\nFILE: server/websocket.ts\n/**\n * WebSocket event bus — Live event streaming for Aedis.\n *\n * The EventBus is the central nervous system for real-time updates.\n * The Coordinator emits events as the build progresses; connected\n * clients receive them over WebSocket. Every event type maps to a\n * specific phase in the build lifecycle.\n */\n\nimport type { WebSocket } from \"ws\";\n\n// ─── Event Types ─────────────────────────────────────────────────────\n\nexport interface AedisEvent {\n  type: AedisEventType;\n  payload: Record<string, unknown>;\n}\n\n/**\n * @deprecated Use AedisEvent. Retained as a type alias for source-level\n * back-compat during the rename cleanup; will be removed in a later\n * release.\n */\nexport type ZendoriumEvent = AedisEvent;\n\nexport type AedisEventType =\n  | \"run_started\"\n  | \"charter_generated\"\n  | \"intent_locked\"\n  | \"task_graph_built\"\n  | \"coherence_check_started\"\n  | \"coherence_check_passed\"\n  | \"coherence_check_failed\"\n  | \"task_started\"\n  | \"worker_assigned\"\n  | \"scout_complete\"\n  | \"builder_complete\"\n  | \"critic_review\"\n  | \"verifier_check\"\n  | \"task_complete\"\n  | \"task_failed\"\n  | \"recovery_attempted\"\n  | \"escalation_triggered\"\n  | \"integration_check\"\n  | \"merge_approved\"\n  | \"merge_blocked\"\n  | \"commit_created\"\n  | \"run_cancelled\"\n  | \"run_complete\"\n  | \"run_receipt\"\n  | \"system_event\"\n  | \"config_event\"\n  | \"execution_verified\"\n  | \"execution_failed\"\n  | \"blast_radius_estimated\"\n  | \"run_summary\"\n  | \"evaluation_started\"\n  | \"evaluation_complete\"\n  | \"evaluation_failed\"\n  | \"trust_updated\"\n  | \"trust_regression\"\n  | \"wave_partial_failure\"\n  | \"adversarial_escalation\";\n\n/**\n * @deprecated Use AedisEventType. Alias kept for downstream code that\n * still imports the old name while we finish the Zendorium → Aedis\n * rename.\n */\nexport type ZendoriumEventType = AedisEventType;\n\n// ─── Wire Protocol ───────────────────────────────────────────────────\n\nexport interface WireMessage {\n  /** Event type */\n  type: AedisEventType;\n  /** Event payload */\n  payload: Record<string, unknown>;\n  /** ISO timestamp */\n  timestamp: string;\n  /** Monotonically increasing sequence number per connection */\n  seq: number;\n}\n\n// ─── Event Bus ───────────────────────────────────────────────────────\n\nexport type EventListener = (event: AedisEvent) => void;\n\nexport interface EventBus {\n  /** Emit an event to all listeners and connected WebSocket clients */\n  emit(event: AedisEvent): void;\n  /** Register a listener for all events */\n  on(listener: EventListener): () => void;\n  /** Register a listener for a specific event type */\n  onType(type: AedisEventType, listener: EventListener): () => void;\n  /** Register a WebSocket client for live streaming */\n  addClient(ws: WebSocket, filter?: AedisEventType[]): void;\n  /** Remove a WebSocket client */\n  removeClient(ws: WebSocket): void;\n  /** Get count of connected clients */\n  clientCount(): number;\n  /** Get recent event history (for late-joining clients) */\n  recentEvents(limit?: number): WireMessage[];\n}\n\n// ─── Implementation ──────────────────────────────────────────────────\n\ninterface ClientEntry {\n  ws: WebSocket;\n  filter: Set<AedisEventType> | null; // null = all events\n  seq: number;\n}\n\nexport function createEventBus(historySize: number = 100): EventBus {\n  const listeners: EventListener[] = [];\n  const typeListeners = new Map<AedisEventType, EventListener[]>();\n  const clients = new Map<WebSocket, ClientEntry>();\n  const history: WireMessage[] = [];\n  let globalSeq = 0;\n\n  function emit(event: AedisEvent): void\n// ... [truncated]",
        "rawModelResponse": "// TEST_REPO_PATH_BUG\n/**\n * Aedis Server — Fastify + WebSocket on port 18796.\n *\n * Entry point for the Aedis API. Mounts all route files,\n * connects to the Coordinator, and streams events over WebSocket.\n * Serves ui/ as static files at / and /ui/*.\n *\n * Can be run directly: node server/index.js\n */\n\nimport \"dotenv/config\";\n\nimport { existsSync, readFileSync } from \"fs\";\nimport { fileURLToPath } from \"url\";\nimport { dirname, join } from \"path\";\nimport Fastify from \"fastify\";\nimport websocket from \"@fastify/websocket\";\nimport fastifyStatic from \"@fastify/static\";\nimport cors from \"@fastify/cors\";\n\nimport { createTailscaleAuth } from \"./middleware/auth.js\";\nimport { createEventBus, type EventBus } from \"./websocket.js\";\nimport { Coordinator, type CoordinatorConfig } from \"../core/coordinator.js\";\nimport { ReceiptStore } from \"../core/receipt-store.js\";\nimport {\n  createCustomHook,\n  createTypecheckHook,\n  type ToolHook,\n  type VerificationPipelineConfig,\n} from \"../core/verification-pipeline.js\";\nimport { WorkerRegistry } from \"../workers/base.js\";\nimport { ScoutWorker } from \"../workers/scout.js\";\nimport { BuilderWorker } from \"../workers/builder.js\";\nimport { CriticWorker } from \"../workers/critic.js\";\nimport { VerifierWorker } from \"../workers/verifier.js\";\nimport { IntegratorWorker } from \"../workers/integrator.js\";\nimport type { TrustProfile } from \"../router/trust-router.js\";\n\nimport { costRoutes } from \"./routes/cost.js\";\nimport { taskRoutes } from \"./routes/tasks.js\";\nimport { runRoutes } from \"./routes/runs.js\";\nimport { workerRoutes } from \"./routes/workers.js\";\nimport { healthRoutes } from \"./routes/health.js\";\nimport { configRoutes } from \"./routes/config.js\";\nimport { providerRoutes } from \"./routes/providers.js\";\nimport { metricsRoutes } from \"./routes/metrics.js\";\nimport { loquiRoutes } from \"./routes/loqui.js\";\nimport { trustRoutes } from \"./routes/trust.js\";\nimport { proveRoutes } from \"./routes/prove.js\";\nimport { reliabilityRoutes } from \"./routes/reliability.js\";\nimport { campaignRoutes } from \"./routes/campaign.js\";\nimport { sessionRoutes } from \"./routes/sessions.js\";\nimport { memoryRoutes } from \"./routes/memory.js\";\n\n// ─── Types ───────────────────────────────────────────────────────────\n\nexport interface ServerConfig {\n  port: number;\n  host: string;\n  projectRoot: string;\n  coordinatorConfig?: Partial<CoordinatorConfig>;\n  /** Disable Tailscale auth (for local dev) */\n  disableAuth?: boolean;\n  /** Additional allowed CIDRs */\n  allowedCidrs?: string[];\n}\n\nconst DEFAULT_CONFIG: ServerConfig = {\n  port: 18796,\n  host: \"0.0.0.0\",\n  projectRoot: process.cwd(),\n};\n\n// ─── Server Context (shared across routes) ───────────────────────────\n\nexport interface ServerContext {\n  coordinator: Coordinator;\n  eventBus: EventBus;\n  receiptStore: ReceiptStore;\n  workerRegistry: WorkerRegistry;\n  config: ServerConfig;\n  startedAt: string;\n}\n\n// ─── Defaults for standalone boot ────────────────────────────────────\n\nfunction defaultTrustProfile(): TrustProfile {\n  return {\n    scores: new Map(),\n    tierThresholds: { fast: 0.6, standard: 0.75, premium: 0.9 },\n  };\n}\n\n/**\n * Build a WorkerRegistry with all 5 worker types registered.\n */\n/**\n * Detect the primary language/stack of a project so the verifier can\n * pick the right hooks. Returns an ordered list of detected stacks —\n * a repo with both package.json AND pyproject.toml (rare but real)\n * gets both. Godot projects are detected via project.godot.\n */\nfunction detectProjectStacks(projectRoot: string): ReadonlyArray<\"typescript\" | \"python\" | \"godot\" | \"rust\" | \"go\" | \"unknown\"> {\n  const stacks: Array<\"typescript\" | \"python\" | \"godot\" | \"rust\" | \"go\" | \"unknown\"> = [];\n  if (existsSync(join(projectRoot, \"tsconfig.json\")) || existsSync(join(projectRoot, \"package.json\"))) {\n    stacks.push(\"typescript\");\n  }\n  if (\n    existsSync(join(projectRoot, \"pyproject.toml\")) ||\n    existsSync(join(projectRoot, \"requirements.txt\")) ||\n    existsSync(join(projectRoot, \"setup.py\")) ||\n    existsSync(join(projectRoot, \"Pipfile\"))\n  ) {\n    stacks.push(\"python\");\n  }\n  if (existsSync(join(projectRoot, \"project.godot\"))) stacks.push(\"godot\");\n  if (existsSync(join(projectRoot, \"Cargo.toml\"))) stacks.push(\"rust\");\n  if (existsSync(join(projectRoot, \"go.mod\"))) stacks.push(\"go\");\n  if (stacks.length === 0) stacks.push(\"unknown\");\n  return stacks;\n}\n\nfunction buildVerificationConfig(projectRoot: string): Partial<VerificationPipelineConfig> {\n  const hooks: ToolHook[] = [];\n  let scripts: Record<string, string> = {};\n  const stacks = detectProjectStacks(projectRoot);\n  console.log(`[server] project stacks detected at ${projectRoot}: ${stacks.join(\", \")}`);\n\n  const packageJsonPath = join(projectRoot, \"package.json\");\n  if (existsSync(packageJsonPath)) {\n    try {\n      const packageJson = JSON.parse(readFileSync(packageJsonPath, \"utf-8\")) as {\n        scripts?: Record<string, string>;\n      };\n      scripts = packageJson.scripts ?? {};\n    } catch {\n      scripts = {};\n    }\n  }\n\n  if (typeof scripts.lint === \"string\" && scripts.lint.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Lint\",\n      command: \"npm\",\n      args: [\"run\", \"lint\"],\n      kind: \"lint\",\n    }));\n  }\n\n  const tsconfigPath = join(projectRoot, \"tsconfig.json\");\n  if (existsSync(tsconfigPath)) {\n    hooks.push(createTypecheckHook({ project: tsconfigPath }));\n  }\n\n  if (typeof scripts.test === \"string\" && scripts.test.trim()) {\n    hooks.push(createCustomHook({\n      name: \"Tests\",\n      command: \"npm\",\n      args: [\"run\", \"test\"],\n      kind: \"tests\",\n    }));\n  }\n\n  // Language-agnostic hooks. The verifier runs every registered hook\n  // against the ACTIVE workspace at dispatch time (cwd is per-run, not\n  // per-boot). We can't know at boot whether a given run will target a\n  // Python repo or a Godot repo — so we register the hooks\n  // unconditionally, guarded by their own \"are there files to check?\"\n  // logic, and let them no-op on repos that don't match.\n  //\n  // Python: syntax-check every .py file with python3 -m py_compile. On\n  // a TS repo with no .py files, `xargs -r` makes the command a no-op\n  // and exits 0. On a Python repo it catches import typos / unmatched\n  // parens / unterminated strings. Only registered if python3 is on\n  // PATH.\n  if (hasExecutableOnPath(\"python3\")) {\n    hooks.push(createCustomHook({\n      name: \"Python Syntax\",\n      command: \"sh\",\n      args: [\"-c\", \"find . -type f -name '*.py' -not -path './.venv/*' -not -path './venv/*' -not -path './__pycache__/*' -not -path './node_modules/*' -not -path './.git/*' 2>/dev/null | head -500 | xargs -r python3 -m py_compile\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Godot: headless --check-only validates scripts + scenes. The\n  // `--check-only` flag exits 0 on success, nonzero if any script\n  // fails to parse. Only registered if the godot binary is on PATH\n  // AND this run's cwd has a project.godot — the sh wrapper short-\n  // circuits on non-Godot repos.\n  if (hasExecutableOnPath(\"godot\")) {\n    hooks.push(createCustomHook({\n      name: \"Godot Check\",\n      command: \"sh\",\n      args: [\"-c\", \"[ -f project.godot ] || exit 0; godot --headless --quit --check-only\"],\n      kind: \"typecheck\",\n    }));\n  }\n\n  // Required checks: whichever typecheck-class hooks we managed to\n  // register. An empty list means the verifier won't fail closed on\n  // \"missing required checks\" — for an unknown-stack repo, the diff /\n  // contract / cross-file stages still run and still gate.\n  const requiredChecks = hooks.some((h) => h.kind === \"typecheck\")\n    ? [\"typecheck\"] as const\n    : [] as const;\n\n  return {\n    hooks,\n    requiredChecks: [...requiredChecks],\n    strictMode: process.env[\"AEDIS_STRICT_MODE\"] === \"true\",\n  };\n}\n\n/**\n * Cheap which(1): returns true if the command resolves on PATH. Used\n * so we don't register hooks that would blow up with ENOENT.\n */\nfunction hasExecutableOnPath(cmd: string): boolean {\n  try {\n    const paths = (process.env[\"PATH\"] ?? \"\").split(\":\").filter(Boolean);\n    for (const p of paths) {\n      if (existsSync(join(p, cmd))) return true;\n    }\n    return false;\n  } catch {\n    return false;\n  }\n}\n\nfunction buildDefaultRegistry(projectRoot: string, verificationConfig: Partial<VerificationPipelineConfig>): WorkerRegistry {\n  const registry = new WorkerRegistry();\n  registry.register(new ScoutWorker({ projectRoot }));\n  registry.register(new BuilderWorker({ projectRoot }));\n  registry.register(new CriticWorker({ projectRoot }));\n  registry.register(new VerifierWorker({\n    hooks: verificationConfig.hooks ?? [],\n    verificationConfig,\n  }));\n  registry.register(new IntegratorWorker());\n  console.log(\"[server] WorkerRegistry: 5 workers registered — scout, builder, critic, verifier, integrator\");\n  return registry;\n}\n\n// ─── Resolve ui/ directory relative to this file ─────────────────────\n\nconst __filename = fileURLToPath(import.meta.url);\nconst __dirname = dirname(__filename);\n\nfunction resolveUiRoot(): string {\n  const siblingUi = join(__dirname, \"..\", \"ui\");\n  if (existsSync(siblingUi)) return siblingUi;\n\n  // Built output lives in dist/server, while source ui/ stays at repo-root/ui.\n  const repoUi = join(__dirname, \"..\", \"..\", \"ui\");\n  if (existsSync(repoUi)) return repoUi;\n\n  return siblingUi;\n}\n\nconst UI_ROOT = resolveUiRoot();\n\n// ─── Boot ────────────────────────────────────────────────────────────\n\nexport async function createServer(\n  config: Partial<ServerConfig> = {},\n  trustProfile?: TrustProfile,\n  workerRegistry?: WorkerRegistry\n): Promise<ReturnType<typeof Fastify>> {\n  const cfg: ServerConfig = { ...DEFAULT_CONFIG, ...config };\n  const verificationConfig = buildVerificationConfig(cfg.projectRoot);\n  const registry = workerRegistry ?? buildDefaultRegistry(cfg.projectRoot, verificationConfig);\n  const profile = trustProfile ?? defaultTrustProfile();\n\n  const eventBus = createEventBus();\n  const receiptStore = new ReceiptStore(cfg.projectRoot);\n  const recovery = await receiptStore.markIncompleteRunsCrashed(\n    `Server restarted on ${new Date().toISOString()} before the run reached a terminal state`,\n  );\n  if (recovery.runsRecovered > 0) {\n    console.log(\n      `[server] STARTUP RECOVERY: ${recovery.runsRecovered} run(s) marked INTERRUPTED; ` +\n      `orphan workspaces=${recovery.orphanWorkspaces.length} ` +\n      `(removed=${recovery.orphanWorkspaces.filter((o) => o.removed).length})`,\n    );\n    for (const orphan of recovery.orphanWorkspaces) {\n      console.log(\n        `[server] STARTUP RECOVERY: workspace ${orphan.workspacePath} — ` +\n        (orphan.removed ? \"cleaned\" : `FAILED: ${orphan.error ?? \"unknown\"}`),\n      );\n    }\n  }\n\n  // Auto-promote is opt-in via env (AEDIS_AUTO_PROMOTE=true). When set,\n  // a run that finishes with a clean VERIFIED_SUCCESS classification\n  // has its workspace commit automatically applied to the source repo\n  // as a real commit. Without it, runs land in the workspace only and\n  // require an explicit POST /tasks/:id/promote.\n  const autoPromoteOnSuccess = process.env[\"AEDIS_AUTO_PROMOTE\"] === \"true\";\n  if (autoPromoteOnSuccess) {\n    console.log(\"[server] AEDIS_AUTO_PROMOTE=true — clean runs will auto-promote to source repo\");\n  }\n\n  const coordinator = new Coordinator(\n    {\n      projectRoot: cfg.projectRoot,\n      verificationConfig,\n      autoPromoteOnSuccess,\n      ...cfg.coordinatorConfig,\n    },\n    profile,\n    registry,\n    eventBus,\n    receiptStore,\n  );\n\n  const ctx: ServerContext = {\n    coordinator,\n    eventBus,\n    receiptStore,\n    workerRegistry: registry,\n    config: cfg,\n    startedAt: new Date().toISOString(),\n  };\n\n  // ─── Fastify instance ──────────────────────────────────────────\n\n  const server = Fastify({\n    logger: {\n      level: \"info\",\n    },\n  });\n\n  // ─── Plugins ───────────────────────────────────────────────────\n\n  await server.register(cors, {\n    origin: true,\n    methods: [\"GET\", \"POST\", \"DELETE\", \"OPTIONS\"],\n  });\n\n  await server.register(websocket);\n\n  // ─── Static files: ui/ at /ui/* ────────────────────────────────\n\n  await server.register(fastifyStatic, {\n    root: UI_ROOT,\n    prefix: \"/ui/\",\n  });\n\n  // ─── GET / → serve ui/index.html directly ─────────────────────\n\n  const indexHtmlPath = join(UI_ROOT, \"index.html\");\n  let indexHtml: string;\n  try {\n    indexHtml = readFileSync(indexHtmlPath, \"utf-8\");\n  } catch {\n    indexHtml = \"<html><body><h1>Aedis</h1><p>ui/index.html not found</p></body></html>\";\n  }\n\n  server.get(\"/\", async (_request, reply) => {\n    reply.type(\"text/html\").send(indexHtml);\n  });\n\n  // ─── Auth middleware ───────────────────────────────────────────\n\n  server.addHook(\n    \"onRequest\",\n    createTailscaleAuth({\n      enabled: !cfg.disableAuth,\n      allowedCidrs: cfg.allowedCidrs ?? [],\n    })\n  );\n\n  // ─── Decorate with context ────────────────────────────────────\n\n  server.decorate(\"ctx\", ctx);\n\n  // ─── Routes ────────────────────────────────────────────────────\n\n  await server.register(taskRoutes, { prefix: \"/tasks\" });\n  await server.register(runRoutes, { prefix: \"/runs\" });\n  await server.register(workerRoutes, { prefix: \"/workers\" });\n  // External API layer — /api/* mirrors the internal routes for external consumers\n  // (Crucibulum, CLI tools) that expect the /api prefix convention.\n  await server.register(workerRoutes, { prefix: \"/api/workers\" });\n  await server.register(taskRoutes, { prefix: \"/api/tasks\" });\n  await server.register(sessionRoutes, { prefix: \"/api/sessions\" });\n  await server.register(runRoutes, { prefix: \"/api/runs\" });\n  await server.register(metricsRoutes, { prefix: \"/api/metrics\" });\n  await server.register(healthRoutes);\n  await server.register(configRoutes, { prefix: \"/config\" });\n  await server.register(providerRoutes, { prefix: \"/config/providers\" });\n  // Metrics + External API Layer v1 — read-only external surface.\n  await server.register(costRoutes, { prefix: \"/cost\" });\n  await server.register(metricsRoutes, { prefix: \"/metrics\" });\n  await server.register(loquiRoutes, { prefix: \"/loqui\" });\n  await server.register(trustRoutes, { prefix: \"/trust\" });\n  await server.register(proveRoutes, { prefix: \"/prove\" });\n  await server.register(reliabilityRoutes, { prefix: \"/reliability\" });\n  await server.register(campaignRoutes, { prefix: \"/campaign\" });\n  await server.register(sessionRoutes, { prefix: \"/sessions\" });\n  await server.register(memoryRoutes, { prefix: \"/memory\" });\n\n  // ─── Approval gate endpoints ──────────────────────────────────\n\n  server.get(\"/approvals/pending\", async (_req, reply) => {\n    const pending = coordinator.getPendingApprovals();\n    reply.send({ ok: true, pending });\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/approve\", async (req, reply) => {\n    const result = await coordinator.approveRun(req.params.runId);\n    reply.send(result);\n  });\n\n  server.post<{ Params: { runId: string } }>(\"/approvals/:runId/reject\", async (req, reply) => {\n    const result = await coordinator.rejectRun(req.params.runId);\n    reply.send(result);\n  });\n\n  // ─── WebSocket endpoint ────────────────────────────────────────\n\n  server.register(async function (fastify) {\n    fastify.get(\"/ws\", { websocket: true }, (socket /* WebSocket */, req) => {\n\n      // P